// Start timer and extract request data
const items = $input.all();
const results = [];

for (const item of items) {
  const body = item.json.body || item.json;
  const headers = item.json.headers || {};
  const startTime = Date.now();

  if (!body.query || typeof body.query !== 'string' || body.query.trim().length === 0) {
    throw new Error('Missing or empty query field');
  }

  results.push({
    json: {
      query: body.query.trim(),
      process_line: body.process_line || null,
      shift: body.shift || null,
      target_indexes: body.target_indexes || ['sop', 'fmea', 'rca', 'maintenance'],
      top_k: body.top_k || 10,
      authorization: headers.authorization || headers.Authorization || '',
      _metrics: {
        start_time: startTime,
        query_id: `qry-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`
      }
    }
  });
}

return results;

// Validate JWT / OAuth2 token
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const authHeader = data.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    throw new Error('UNAUTHORIZED: Missing or invalid Authorization header. Expected: Bearer <token>');
  }

  const token = authHeader.replace('Bearer ', '');

  // Decode JWT payload (base64url)
  // In production, verify signature with public key / JWKS endpoint
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid JWT format');
    }

    const payloadB64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const payload = JSON.parse(Buffer.from(payloadB64, 'base64').toString('utf-8'));

    // Check expiration
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < now) {
      throw new Error('JWT token has expired');
    }

    // Extract user info
    const userId = payload.sub || payload.user_id || 'unknown';
    const userRole = payload.role || payload.user_role || 'viewer';
    const userProcessLines = payload.process_lines || payload.allowed_process_lines || ['*'];

    results.push({
      json: {
        ...data,
        user_id: userId,
        user_role: userRole,
        user_process_lines: userProcessLines,
        jwt_valid: true
      }
    });
  } catch (e) {
    if (e.message.includes('JWT') || e.message.includes('expired')) {
      throw e;
    }
    throw new Error(`UNAUTHORIZED: Failed to decode JWT - ${e.message}`);
  }
}

return results;

// Enforce RBAC: check user_role against allowed indexes and process_lines
const items = $input.all();
const results = [];

// RBAC policy map (loaded from DB in production; inline for workflow portability)
const rbacPolicies = {
  'admin':     { indexes: ['sop','fmea','rca','maintenance'], lines: ['*'], canQuery: true },
  'engineer':  { indexes: ['sop','fmea','rca','maintenance'], lines: ['*'], canQuery: true },
  'operator':  { indexes: ['sop','maintenance'],              lines: ['*'], canQuery: true },
  'inspector': { indexes: ['sop','fmea','rca'],               lines: ['*'], canQuery: true },
  'viewer':    { indexes: ['sop'],                             lines: ['*'], canQuery: true }
};

for (const item of items) {
  const data = item.json;
  const policy = rbacPolicies[data.user_role];

  if (!policy || !policy.canQuery) {
    // Emit RBAC rejection metric flag
    throw new Error(`RBAC_REJECTION: Role '${data.user_role}' is not authorized to query`);
  }

  // Filter requested indexes to only allowed ones
  const allowedIndexes = data.target_indexes.filter(idx => policy.indexes.includes(idx));
  if (allowedIndexes.length === 0) {
    throw new Error(`RBAC_REJECTION: Role '${data.user_role}' has no access to requested indexes: ${data.target_indexes.join(', ')}`);
  }

  // Check process_line access
  if (data.process_line && !policy.lines.includes('*')) {
    if (!policy.lines.includes(data.process_line)) {
      throw new Error(`CROSS_PROCESS_ACCESS: Role '${data.user_role}' cannot access process line '${data.process_line}'`);
    }
  }

  results.push({
    json: {
      ...data,
      target_indexes: allowedIndexes,
      rbac_passed: true,
      rbac_filtered_indexes: data.target_indexes.length - allowedIndexes.length
    }
  });
}

return results;

// Detect prompt injection attacks
const items = $input.all();
const results = [];

// Prompt injection patterns
const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|above|prior)\s+(instructions|prompts|rules)/i,
  /disregard\s+(all\s+)?(previous|above|prior)/i,
  /you\s+are\s+now\s+(a|an|the)\s+/i,
  /pretend\s+(you\s+are|to\s+be)/i,
  /act\s+as\s+(a|an|if)/i,
  /system\s*:\s*/i,
  /\[\s*INST\s*\]/i,
  /<<\s*SYS\s*>>/i,
  /forget\s+(everything|all|your)/i,
  /override\s+(your|the|all)\s+(instructions|rules|guidelines)/i,
  /new\s+instructions?\s*:/i,
  /reveal\s+(your|the)\s+(system|initial|original)\s+(prompt|instructions)/i,
  /what\s+(are|is)\s+your\s+(system|initial)\s+(prompt|instructions)/i,
  /output\s+(your|the)\s+(system|initial)\s+prompt/i,
  /jailbreak/i,
  /DAN\s+mode/i,
  /developer\s+mode/i
];

for (const item of items) {
  const data = item.json;
  const query = data.query;
  let injectionDetected = false;
  let matchedPattern = null;

  for (const pattern of INJECTION_PATTERNS) {
    if (pattern.test(query)) {
      injectionDetected = true;
      matchedPattern = pattern.toString();
      break;
    }
  }

  // Additional heuristic: very long queries or queries with special formatting
  if (!injectionDetected && query.length > 2000) {
    injectionDetected = true;
    matchedPattern = 'query_length_exceeded';
  }

  if (injectionDetected) {
    throw new Error(`PROMPT_INJECTION: Potential prompt injection detected. Pattern: ${matchedPattern}`);
  }

  results.push({
    json: {
      ...data,
      injection_check_passed: true
    }
  });
}

return results;

// Determine if cache hit or miss
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const prevData = $('Detect_Prompt_Injection').item.json;
  const cacheResult = data.result || data.value || null;

  let cacheHit = false;
  let cachedAnswer = null;

  if (cacheResult && cacheResult !== 'null' && cacheResult !== '') {
    try {
      cachedAnswer = JSON.parse(cacheResult);
      if (cachedAnswer && cachedAnswer.answer) {
        cacheHit = true;
      }
    } catch (e) {
      cacheHit = false;
    }
  }

  results.push({
    json: {
      ...prevData,
      cache_hit: cacheHit,
      cached_answer: cachedAnswer,
      _metrics: {
        ...prevData._metrics,
        cache_check_time: Date.now()
      }
    }
  });
}

return results;

// Return cached answer directly with cache-hit metrics
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const endTime = Date.now();
  const latency = (endTime - data._metrics.start_time) / 1000;

  const metrics = [
    `# HELP ai_query_total Total queries processed`,
    `# TYPE ai_query_total counter`,
    `ai_query_total{cache="hit",process_line="${data.process_line || 'all'}"} 1`,
    ``,
    `# HELP ai_query_latency_seconds Query latency`,
    `# TYPE ai_query_latency_seconds histogram`,
    `ai_query_latency_seconds_sum{cache="hit"} ${latency}`,
    `ai_query_latency_seconds_count{cache="hit"} 1`,
    ``
  ].join('\n');

  results.push({
    json: {
      answer: data.cached_answer.answer,
      confidence_score: data.cached_answer.confidence_score,
      sources: data.cached_answer.sources || [],
      cache_hit: true,
      latency_seconds: latency,
      _prometheus_metrics: metrics,
      _metrics: data._metrics
    }
  });
}

return results;

// Parse embedding response and prepare multi-index search
const items = $input.all();
const results = [];

for (const item of items) {
  const embeddingResp = item.json;
  const prevData = $('Cache_Hit_Check').item.json;

  let embedding = null;
  if (embeddingResp.data && embeddingResp.data[0]) {
    embedding = embeddingResp.data[0].embedding;
  }

  if (!embedding) {
    throw new Error('Failed to generate query embedding');
  }

  const embeddingTime = Date.now();

  // Create one search request per target index
  for (const indexName of prevData.target_indexes) {
    results.push({
      json: {
        ...prevData,
        query_embedding: embedding,
        current_index: indexName,
        _metrics: {
          ...prevData._metrics,
          embedding_time: embeddingTime,
          embedding_latency_ms: embeddingTime - prevData._metrics.start_time
        }
      }
    });
  }
}

return results;

// Merge multi-index results and filter superseded revisions
const items = $input.all();
const sourceItems = $('Prepare_Multi_Index_Search').all();
const allResults = [];
let queryData = null;

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;
  const src = (sourceItems[i] || sourceItems[0] || { json: {} }).json;
  if (!queryData) queryData = src;

  const results = data.result || data.points || [];
  for (const r of results) {
    allResults.push({
      id: r.id,
      score: r.score,
      payload: r.payload || {},
      index: src.current_index || 'unknown'
    });
  }
}

const vectorSearchTime = Date.now();

// Filter out superseded revisions
// Group by doc_id, keep only highest revision_number
const docRevisions = {};
for (const r of allResults) {
  const docId = r.payload.doc_id || r.id;
  const revNum = r.payload.revision_number || 1;
  if (!docRevisions[docId] || docRevisions[docId].revision_number < revNum) {
    docRevisions[docId] = { ...r, revision_number: revNum };
  }
}

const filteredResults = Object.values(docRevisions);
const supersededCount = allResults.length - filteredResults.length;

// Sort by score descending
filteredResults.sort((a, b) => b.score - a.score);

// Take top_k
const topK = filteredResults.slice(0, (queryData && queryData.top_k) || 10);

const metrics = (queryData && queryData._metrics) ? queryData._metrics : {};
return [{
  json: {
    ...queryData,
    search_results: topK,
    total_results: allResults.length,
    filtered_results: topK.length,
    superseded_filtered: supersededCount,
    matched_indexes: [...new Set(topK.map(r => r.index))],
    matched_doc_ids: topK.map(r => r.payload.doc_id || r.id),
    top_k_scores: topK.map(r => r.score),
    _metrics: {
      ...metrics,
      vector_search_time: vectorSearchTime,
      vector_query_latency_ms: vectorSearchTime - (metrics.embedding_time || metrics.start_time || vectorSearchTime)
    }
  }
}];

// Process reranking results and build LLM context
const items = $input.all();
const results = [];

for (const item of items) {
  const reranked = item.json;
  const prevItem = $('Merge_Filter_Results').item;
  const prevData = (prevItem && prevItem.json) ? prevItem.json : {};
  const rerankTime = Date.now();

  const searchResults = prevData.search_results || [];
  const topKScores = prevData.top_k_scores || [];

  let finalResults = searchResults;
  let rerankScores = topKScores;

  if (reranked.results && Array.isArray(reranked.results) && reranked.results.length > 0) {
    const sorted = reranked.results.slice().sort((a, b) => b.score - a.score).slice(0, 5);
    finalResults = sorted.map(r => searchResults[r.index]).filter(r => r != null);
    rerankScores = sorted.map(r => r.score);
  } else {
    finalResults = searchResults.slice(0, 5);
    rerankScores = topKScores.slice(0, 5);
  }

  const contextParts = finalResults.map((r, i) => {
    const payload = (r && r.payload) ? r.payload : {};
    return `[Source ${i + 1} | Index: ${r ? r.index : 'N/A'} | Doc: ${payload.file_name || 'N/A'} | Line: ${payload.process_line || 'N/A'}]\n${payload.chunk_text || ''}`;
  });
  const context = contextParts.join('\n\n---\n\n');

  const systemPrompt = `You are an Enterprise AI Inspection Knowledge Assistant. Your role is to answer questions about standard operating procedures (SOPs), failure mode and effects analysis (FMEA), root cause analysis (RCA), and maintenance documentation.\n\nRules:\n1. ONLY answer based on the provided context documents.\n2. If the context does not contain enough information, say "I don't have sufficient information in the available documents to answer this question."\n3. Always cite your sources by referencing the Source number and document name.\n4. Be precise and concise. Use technical language appropriate for industrial/manufacturing environments.\n5. If multiple sources provide conflicting information, note the discrepancy.\n6. Never fabricate information not present in the context.`;

  const userPrompt = `Context Documents:\n${context}\n\n---\n\nUser Question: ${prevData.query || ''}\n\nProvide a precise answer based solely on the context above. Cite sources.`;

  results.push({
    json: {
      ...prevData,
      rerank_scores: rerankScores,
      final_results: finalResults,
      context: context,
      system_prompt: systemPrompt,
      user_prompt: userPrompt,
      _metrics: {
        ...(prevData._metrics || {}),
        rerank_time: rerankTime,
        rerank_latency_ms: rerankTime - ((prevData._metrics && prevData._metrics.vector_search_time) ? prevData._metrics.vector_search_time : rerankTime)
      }
    }
  });
}

return results;

// Extract LLM answer and perform hallucination check + confidence scoring
const items = $input.all();
const results = [];

for (const item of items) {
  const llmResp = item.json;
  const prevItem = $('Build_LLM_Context').item;
  const prevData = (prevItem && prevItem.json) ? prevItem.json : {};
  const answerTime = Date.now();

  // Extract answer text
  let answerText = '';
  let tokensUsed = 0;
  if (llmResp.choices && llmResp.choices[0]) {
    answerText = (llmResp.choices[0].message && llmResp.choices[0].message.content) ? llmResp.choices[0].message.content : '';
    tokensUsed = (llmResp.usage && llmResp.usage.total_tokens) ? llmResp.usage.total_tokens : 0;
  }

  if (!answerText) {
    throw new Error('LLM returned empty answer');
  }

  // === HALLUCINATION DETECTION ===
  const context = prevData.context ? prevData.context.toLowerCase() : '';
  const answer = answerText.toLowerCase();

  const unsupportedPhrases = [
    "i don't have sufficient information",
    'not enough information',
    'cannot find relevant',
    'no relevant information',
    'not available in the provided'
  ];
  const isUnsupported = unsupportedPhrases.some(p => answer.includes(p));

  const answerSentences = answerText.split(/[.!?]+/).filter(s => s.trim().length > 20);
  let supportedClaims = 0;
  let totalClaims = 0;

  for (const sentence of answerSentences) {
    if (sentence.toLowerCase().includes('source') && sentence.includes('[')) continue;
    totalClaims++;
    const words = sentence.toLowerCase().split(/\s+/).filter(w => w.length > 4);
    const matchingWords = context ? words.filter(w => context.includes(w)) : [];
    const coverage = words.length > 0 ? matchingWords.length / words.length : 0;
    if (coverage > 0.3) supportedClaims++;
  }

  let confidenceScore = 0.0;
  if (isUnsupported) {
    confidenceScore = 0.0;
  } else if (totalClaims === 0) {
    confidenceScore = 0.5;
  } else {
    const claimSupport = supportedClaims / totalClaims;
    const rerankScores = prevData.rerank_scores || [];
    const avgRerankScore = rerankScores.length > 0
      ? rerankScores.reduce((a, b) => a + (b || 0), 0) / rerankScores.length
      : 0;
    confidenceScore = Math.round((claimSupport * 0.6 + Math.min(avgRerankScore, 1) * 0.4) * 100) / 100;
  }

  const hallucinationFlag = !isUnsupported && totalClaims > 0 && (supportedClaims / totalClaims) < 0.4;
  const costEstimate = tokensUsed * 0.00015 / 1000;

  const prevMetrics = prevData._metrics || {};
  const rerankTime = prevMetrics.rerank_time || answerTime;

  results.push({
    json: {
      ...prevData,
      answer: answerText,
      confidence_score: confidenceScore,
      hallucination_flag: hallucinationFlag,
      is_unsupported: isUnsupported,
      supported_claims: supportedClaims,
      total_claims: totalClaims,
      tokens_used: tokensUsed,
      cost_estimate: costEstimate,
      _metrics: {
        ...prevMetrics,
        answer_time: answerTime,
        answer_generation_latency_ms: answerTime - rerankTime
      }
    }
  });
}

return results;

// Compute all query pipeline Prometheus metrics
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const metrics_data = d._metrics || {};
  const endTime = Date.now();
  const totalLatency = metrics_data.start_time ? (endTime - metrics_data.start_time) / 1000 : 0;
  const embLatency = (metrics_data.embedding_latency_ms || 0) / 1000;
  const vecLatency = (metrics_data.vector_query_latency_ms || 0) / 1000;
  const rerankLatency = (metrics_data.rerank_latency_ms || 0) / 1000;
  const answerLatency = (metrics_data.answer_generation_latency_ms || 0) / 1000;
  const pl = d.process_line || 'all';
  const shift = d.shift || 'unknown';
  const queryId = (metrics_data.query_id) ? String(metrics_data.query_id) : 'unknown';
  const matchedIndexes = Array.isArray(d.matched_indexes) ? d.matched_indexes : [];
  const indexesLabel = matchedIndexes.length > 0 ? matchedIndexes.join(',') : 'none';

  const buckets = [0.1, 0.25, 0.5, 1, 2.5, 5, 10, 30, 60];
  const histLine = (name, labels, val) => {
    const lines = buckets.map(b => `${name}{${labels},le="${b}"} ${val <= b ? 1 : 0}`);
    lines.push(`${name}{${labels},le="+Inf"} 1`);
    lines.push(`${name}_sum{${labels}} ${val}`);
    lines.push(`${name}_count{${labels}} 1`);
    return lines.join('\n');
  };

  const metrics = [
    `# HELP ai_query_total Total queries`,
    `# TYPE ai_query_total counter`,
    `ai_query_total{cache="miss",process_line="${pl}",shift="${shift}",role="${d.user_role || 'unknown'}"} 1`,
    ``,
    `# HELP ai_query_latency_seconds Total query latency`,
    `# TYPE ai_query_latency_seconds histogram`,
    histLine('ai_query_latency_seconds', `process_line="${pl}"`, totalLatency),
    ``,
    `# HELP ai_embedding_latency_seconds Embedding generation latency`,
    `# TYPE ai_embedding_latency_seconds histogram`,
    histLine('ai_embedding_latency_seconds', `model="text-embedding-3-large"`, embLatency),
    ``,
    `# HELP ai_vector_query_latency_seconds Vector DB search latency`,
    `# TYPE ai_vector_query_latency_seconds histogram`,
    histLine('ai_vector_query_latency_seconds', `indexes="${indexesLabel}"`, vecLatency),
    ``,
    `# HELP ai_rerank_latency_seconds Cross-encoder rerank latency`,
    `# TYPE ai_rerank_latency_seconds histogram`,
    histLine('ai_rerank_latency_seconds', `model="cross-encoder"`, rerankLatency),
    ``,
    `# HELP ai_answer_generation_latency_seconds LLM answer generation latency`,
    `# TYPE ai_answer_generation_latency_seconds histogram`,
    histLine('ai_answer_generation_latency_seconds', `model="gpt-4o-mini"`, answerLatency),
    ``,
    `# HELP ai_confidence_score Answer confidence score gauge`,
    `# TYPE ai_confidence_score gauge`,
    `ai_confidence_score{process_line="${pl}",query_id="${queryId}"} ${d.confidence_score || 0}`,
    ``,
    `# HELP ai_hallucination_flag_total Hallucination flags`,
    `# TYPE ai_hallucination_flag_total counter`,
    `ai_hallucination_flag_total{process_line="${pl}"} ${d.hallucination_flag ? 1 : 0}`,
    ``,
    `# HELP ai_unsupported_answers_total Unsupported answers`,
    `# TYPE ai_unsupported_answers_total counter`,
    `ai_unsupported_answers_total{process_line="${pl}"} ${d.is_unsupported ? 1 : 0}`,
    ``,
    `# HELP ai_retrieval_from_superseded_total Superseded docs filtered`,
    `# TYPE ai_retrieval_from_superseded_total counter`,
    `ai_retrieval_from_superseded_total{} ${d.superseded_filtered || 0}`,
    ``
  ].join('\n');

  results.push({
    json: {
      ...d,
      _prometheus_metrics: metrics,
      _total_latency_seconds: totalLatency
    }
  });
}

return results;

// Handle query errors: RBAC rejections, prompt injection, general errors
const items = $input.all();
const results = [];

for (const item of items) {
  const error = item.json;
  const errorMsg = error.message || error.error?.message || 'Unknown query error';
  const nodeName = error.node?.name || error.workflow?.lastNodeExecuted || 'unknown';

  let eventType = 'query_error';
  let metricsLines = [];

  if (errorMsg.includes('RBAC_REJECTION')) {
    eventType = 'rbac_rejection';
    metricsLines = [
      `# HELP ai_rbac_rejections_total RBAC access rejections`,
      `# TYPE ai_rbac_rejections_total counter`,
      `ai_rbac_rejections_total{reason="${errorMsg.substring(16, 80).replace(/"/g, '')}"} 1`
    ];
  } else if (errorMsg.includes('CROSS_PROCESS_ACCESS')) {
    eventType = 'cross_process_access';
    metricsLines = [
      `# HELP ai_cross_process_access_attempts_total Cross-process access attempts`,
      `# TYPE ai_cross_process_access_attempts_total counter`,
      `ai_cross_process_access_attempts_total{} 1`
    ];
  } else if (errorMsg.includes('PROMPT_INJECTION')) {
    eventType = 'prompt_injection';
    metricsLines = [
      `# HELP ai_prompt_injection_attempts_total Prompt injection attempts`,
      `# TYPE ai_prompt_injection_attempts_total counter`,
      `ai_prompt_injection_attempts_total{} 1`
    ];
  } else if (errorMsg.includes('UNAUTHORIZED')) {
    eventType = 'jwt_invalid';
    metricsLines = [
      `# HELP ai_auth_failures_total Authentication failures`,
      `# TYPE ai_auth_failures_total counter`,
      `ai_auth_failures_total{reason="jwt_invalid"} 1`
    ];
  } else {
    metricsLines = [
      `# HELP ai_query_errors_total Query processing errors`,
      `# TYPE ai_query_errors_total counter`,
      `ai_query_errors_total{stage="${nodeName}",error_type="${errorMsg.substring(0, 50).replace(/"/g, '')}"} 1`
    ];
  }

  const metrics = metricsLines.join('\n') + '\n';

  results.push({
    json: {
      error_message: errorMsg,
      event_type: eventType,
      error_node: nodeName,
      timestamp: new Date().toISOString(),
      _prometheus_metrics: metrics
    }
  });
}

return results;
